    const n = nums.length;
    const prefixMod = new Array(n + 1).fill(0);
    let totalSum = 0;
    for (let i = 0; i < n; i++) {
        totalSum += nums[i];
        prefixMod[i + 1] = (prefixMod[i] + nums[i]) % k;
    }

    const modMap = new Map();
    modMap.set(0, 0);
    let sum = 0;
    let result = totalSum;

    for (let i = 1; i <= n; i++) {
        const mod = prefixMod[i];
        if (modMap.has(mod)) {
            const j = modMap.get(mod);
            const subarraySum = prefixMod[i] - prefixMod[j];
            if (subarraySum % k === 0) {
                result = Math.min(result, totalSum - (prefixMod[i] - prefixMod[j]));
